    const MOD = 1e9 + 7;
    const yToXs = new Map();

    for (const [x, y] of points) {
        if (!yToXs.has(y)) {
            yToXs.set(y, []);
        }
        yToXs.get(y).push(x);
    }

    const yList = Array.from(yToXs.keys()).filter(y => yToXs.get(y).length >= 2);
    yList.sort((a, b) => a - b);

    let res = 0;
    const xPairsCount = new Map();
    const keyToCount = new Map();

    for (const y of yList) {
        const xs = yToXs.get(y).sort((a, b) => a - b);
        const pairs = [];

        for (let i = 0; i < xs.length; i++) {
            for (let j = i + 1; j < xs.length; j++) {
                const x1 = xs[i];
                const x2 = xs[j];
                pairs.push([x1, x2]);
                const key = `${x1},${x2}`;
                res = (res + (keyToCount.get(key) || 0)) % MOD;
            }
        }

        for (const [x1, x2] of pairs) {
            const key = `${x1},${x2}`;
            keyToCount.set(key, (keyToCount.get(key) || 0) + 1);
