use std::collections::HashMap;

fn solve(points: Vec<Vec<i64>>) -> i64 {
    const MOD: i64 = 1_000_000_007;
    let mut y_to_xs: HashMap<i64, Vec<i64>> = HashMap::new();

    for point in points {
        let x = point[0];
        let y = point[1];
        y_to_xs.entry(y).or_default().push(x);
    }

    let mut y_list: Vec<i64> = y_to_xs.iter()
        .filter(|(_, xs)| xs.len() >= 2)
        .map(|(&y, _)| y)
        .collect();
    y_list.sort_unstable();

    let mut res = 0;
    let mut key_to_count: HashMap<String, i64> = HashMap::new();

    for y in y_list {
        let xs = y_to_xs.get(&y).unwrap();
        let mut xs_sorted = xs.clone();
        xs_sorted.sort_unstable();
        let mut pairs = Vec::new();

        for i in 0..xs_sorted.len() {
            for j in i + 1..xs_sorted.len() {
                let x1 = xs_sorted[i];
                let x2 = xs_sorted[j];
                pairs.push((x1, x2));
                let key = format!("{},{}", x1, x2);
                res = (res + key_to_count.get(&key).unwrap_or(&0)) % MOD;
            }
        }

        for (x1, x2) in pairs {
            let key = format!("{},{}", x1, x2);
            *key_to_count.entry(key).or_insert(0) += 1;
        }
    }

    res
}
